INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'eb55d083-0297-4a6a-94a5-0e1a9d6c8ded',
  '00000000-0000-0000-0000-000000000001',
  $escape$Foundry Fundamentals: Mastering Solidity Basics with Forge$escape$,
  $escape$When building smart contracts with Foundry, understanding Solidity fundamentals is crucial. State variables can be declared as public, internal, or private, with the latter being inaccessible from outside the contract. Functions can have various visibility modifiers, including external, public, internal, and private. Modifiers can be used to restrict function execution based on conditions. Forge, Foundry's testing framework, allows you to write comprehensive tests for your contracts. By leveraging these features, you can ensure your contracts are secure, efficient, and well-tested.$escape$,
  $escape$contract MyContract { uint public myVariable; function myFunction() public { require(msg.sender == owner, 'Only owner can call'); } }$escape$,
  $escape$solidity$escape$,
